def gen(rng, size):
    n = max(2, size)
    seen = set()
    pts = []
    while len(pts) < n:
        x, y = rng.randint(-10**6, 10**6), rng.randint(-10**6, 10**6)
        if (x, y) not in seen:
            seen.add((x, y))
            pts.append([x, y])
    return [pts]

