class Solution:
    def minCostConnectPoints(self, points):
        n = len(points)
        if n == 1:
            return 0
        visited = [False] * n
        min_dist = [float('inf')] * n
        min_dist[0] = 0
        total = 0
        for _ in range(n):
            u = -1
            for v in range(n):
                if not visited[v] and (u == -1 or min_dist[v] < min_dist[u]):
                    u = v
            visited[u] = True
            total += min_dist[u]
            for v in range(n):
                if not visited[v]:
                    d = abs(points[u][0] - points[v][0]) + abs(points[u][1] - points[v][1])
                    if d < min_dist[v]:
                        min_dist[v] = d
        return total

